\input{sections/conclusions.tex}

\begin{acknowledgments}
% TODO(acknowledgments): add funding sources (NSF/DOE grant numbers for
% CHIME/FRB and DSA-110), telescope-operations acknowledgments, DESI/Legacy
% Surveys and NED data acknowledgments, and individual thanks.
The authors thank the CHIME/FRB and DSA-110 collaborations.
\end{acknowledgments}

\section*{Data Availability}
\label{sec:data-availability}
% TODO(data-availability): before submission: (i) make the pipeline repo
% public and pin the release tag used for the accepted version; (ii) state
% where the dynamic spectra and fit products live and under what access
% policy.
The dynamic spectra, fit products, and foreground-census tables supporting
this work will be made available upon publication. The reduction and fitting
pipeline is publicly available at
\url{https://github.com/jakobtfaber/dsa110-FLITS}; the accepted version of
this manuscript corresponds to a tagged release of that repository.

\facilities{CHIME, OVRO:DSA-110}

\software{\texttt{astropy} \citep{astropy2013, astropy2018, astropy2022},
\texttt{dynesty} \citep{Speagle2020}, \texttt{numpy}, \texttt{scipy},
\texttt{matplotlib}, \texttt{pygedm} \citep{Price2021} (NE2001/YMW16),
\texttt{mwprop} \citep{Ocker2026} (NE2025), and the open-source co-detection
reduction and fitting pipeline
(\url{https://github.com/jakobtfaber/dsa110-FLITS}).
}

\appendix
\input{sections/appendix.tex}
% The exponential-PBF appendix is parked for now because the manuscript is not
% yet ready to quote any alpha-limit result language.
% \input{sections/emg_alpha4_appendix.tex}

\bibliographystyle{aasjournal}
\bibliography{bib/refs}

\end{document}

